// Verify required caches exist
const response = $input.first().json;
const requiredCaches = ['project-kb', 'project-deliverables'];

let cacheList = [];
let apiError = false;

try {
  if (response.body && response.body.cachedContents) {
    cacheList = response.body.cachedContents;
  } else if (response.cachedContents) {
    cacheList = response.cachedContents;
  } else if (response.statusCode && response.statusCode !== 200) {
    apiError = true;
  }
} catch (e) {
  apiError = true;
}

const existingNames = cacheList.map(c => c.displayName || c.name || '');

const missingCaches = requiredCaches.filter(req => {
  return !existingNames.some(existing => 
    existing.toLowerCase().includes(req.toLowerCase())
  );
});

// Check for expired caches (within 30 min of expiry)
const soonExpiring = [];
const now = new Date();
const thirtyMinMs = 30 * 60 * 1000;

cacheList.forEach(cache => {
  if (cache.expireTime) {
    const expiry = new Date(cache.expireTime);
    if (expiry - now < thirtyMinMs && expiry > now) {
      soonExpiring.push({
        name: cache.displayName || cache.name,
        expires_at: cache.expireTime,
        minutes_remaining: Math.round((expiry - now) / 60000)
      });
    }
  }
});

return [{
  json: {
    api_error: apiError,
    total_caches: cacheList.length,
    existing_names: existingNames,
    required_caches: requiredCaches,
    missing_caches: missingCaches,
    soon_expiring: soonExpiring,
    has_issues: apiError || missingCaches.length > 0 || soonExpiring.length > 0,
    checked_at: new Date().toISOString()
  }
}];

// Silent success — no action needed
// Log for audit purposes
return [{
  json: {
    action: 'CACHE_CHECK_OK',
    total_caches: $input.first().json.total_caches,
    checked_at: $input.first().json.checked_at,
    message: 'All required caches present and healthy'
  }
}];
